code = """import pandas as pd, json
opp = pd.DataFrame(var_call_xQ1qZo3GU9J8BhJTQ640BHlc)
qli = pd.DataFrame(var_call_Xl77JoE0lgaSzg50gPqClzoP)
# normalize ids
opp['opp_norm']=opp['OpportunityId'].str.replace('#','', regex=False).str.strip()
opp['agent_norm']=opp['AgentId'].str.replace('#','', regex=False).str.strip()
qli['opp_norm']=qli['OpportunityId'].str.replace('#','', regex=False).str.strip()
# numeric
qli['Quantity']=pd.to_numeric(qli['Quantity'])
qli['UnitPrice']=pd.to_numeric(qli['UnitPrice'])
qli['sales']=qli['Quantity']*qli['UnitPrice']
# sum per opp then per agent
sales_per_opp = qli.groupby('opp_norm', as_index=False)['sales'].sum()
merged = sales_per_opp.merge(opp[['opp_norm','agent_norm']], on='opp_norm', how='left')
sales_per_agent = merged.groupby('agent_norm', as_index=False)['sales'].sum().sort_values('sales', ascending=False)
top_agent = sales_per_agent.iloc[0]['agent_norm'] if len(sales_per_agent)>0 else None
print('__RESULT__:')
print(json.dumps({'top_agent_id': top_agent, 'sales_per_agent': sales_per_agent.head(5).to_dict(orient='records')}))"""

